module asyn_fifo (
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [7:0] wdata,
    output wfull,
    output rempty,
    output [7:0] rdata
);

parameter WIDTH = 8;
parameter DEPTH = 16;

wire wen, ren;
wire [WIDTH-1:0] wdata_in;
wire [WIDTH-1:0] rdata_out;
reg [WIDTH-1:0] ram_mem [0:DEPTH-1];

reg [$clog2(DEPTH)-1:0] waddr_bin;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn)
        waddr_bin <= 0;
    else if (winc)
        waddr_bin <= waddr_bin + 1;
end

reg [$clog2(DEPTH)-1:0] raddr_bin;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn)
        raddr_bin <= 0;
    else if (rinc)
        raddr_bin <= raddr_bin + 1;
end

wire [$clog2(DEPTH)-1:0] wptr;
genvar i;
    for (i = 0; i < $clog2(DEPTH); i = i + 1) begin : gen_gray_code_wptr
        end // Auto-repaired
        assign wptr[i] = (i == 0) ? waddr_bin[i] : waddr_bin[i] ^ waddr_bin[i-1];
    end

wire [$clog2(DEPTH)-1:0] rptr;
    for (i = 0; i < $clog2(DEPTH); i = i + 1) begin : gen_gray_code_rptr
        assign rptr[i] = (i == 0) ? raddr_bin[i] : raddr_bin[i] ^ raddr_bin[i-1];
    end

reg [$clog2(DEPTH)-1:0] wptr_buff;
reg [$clog2(DEPTH)-1:0] rptr_buff;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn)
        wptr_buff <= 0;
        wptr_buff <= wptr;
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn)
        rptr_buff <= 0;
        rptr_buff <= rptr;
end

assign wfull = (wptr == {~rptr_buff[$clog2(DEPTH)-1], rptr_buff[$clog2(DEPTH)-2:0]});
assign rempty = (rptr == wptr);

assign wen = winc && !wfull;
assign ren = rinc && !rempty;
assign wdata_in = wdata;

integer j;
always @(posedge wclk) begin
    if (wen) begin
        ram_mem[waddr_bin] <= wdata_in;
    end
end

always @(posedge rclk) begin
    if (ren) begin
        rdata_out <= ram_mem[raddr_bin];
    end
end

assign rdata = rdata_out;

endmodule
